// =====================================
// GET DATE FROM INPUT NODE (ROBUST)
// =====================================

let inputDateRaw = $input.first().json.date;

if (!inputDateRaw) {
  throw new Error("Input date missing");
}

// Remove ordinal suffix (st, nd, rd, th)
inputDateRaw = String(inputDateRaw).replace(/(\d+)(st|nd|rd|th)/gi, "$1");

// Parse Date
const parsedDate = new Date(inputDateRaw);

if (isNaN(parsedDate.getTime())) {
  throw new Error("Invalid date format: " + inputDateRaw);
}

// Convert to YYYY-MM-DD
const targetDateString = parsedDate.toISOString().split("T")[0];


// =====================================
// PROCESS ALL INPUT ITEMS
// =====================================

const inputItems = $input.all();
const results = [];

for (const item of inputItems) {

  // Flexible column name support
  const leetcodeUrlRaw =
    item.json['Leetcode Url'] ||
    item.json['Leetcode URL'] ||
    item.json['leetcode_url'] ||
    item.json['url'] ||
    null;

  if (!leetcodeUrlRaw) {
    results.push({
      json: {
        error: "Leetcode Url missing",
        originalData: item.json
      }
    });
    continue;
  }

  const leetcodeUrl = String(leetcodeUrlRaw).trim();

  // =====================================
  // EXTRACT USERNAME
  // =====================================

  let username = "";

  const match = leetcodeUrl.match(/leetcode\.com\/(?:u\/)?([^\/\s]+)/);

  if (match && match[1]) {
    username = match[1];
  } else if (!leetcodeUrl.includes("/")) {
    username = leetcodeUrl;
  }

  if (!username) {
    results.push({
      json: {
        error: "Unable to extract username",
        leetcodeUrl
      }
    });
    continue;
  }

  // =====================================
  // GRAPHQL QUERY
  // =====================================

  const query = `
  query getRecentAc($username: String!) {
    recentAcSubmissionList(username: $username, limit: 200) {
      id
      title
      timestamp
    }
  }
  `;

  let solvedProblems = [];

  try {

    const response = await this.helpers.httpRequest({
      method: "POST",
      url: "https://leetcode.com/graphql",
      headers: {
        "Content-Type": "application/json",
        "Referer": "https://leetcode.com",
        "User-Agent": "Mozilla/5.0"
      },
      body: {
        query,
        variables: { username }
      },
      json: true
    });

    if (response?.data?.recentAcSubmissionList) {

      const submissions = response.data.recentAcSubmissionList;
      const solvedSet = new Set();

      for (const submission of submissions) {

        const submissionDate = new Date(
          parseInt(submission.timestamp) * 1000
        ).toISOString().split("T")[0];

        if (submissionDate === targetDateString) {
          solvedSet.add(submission.title);
        }
      }

      solvedProblems = Array.from(solvedSet);
    }

  } catch (err) {
    results.push({
      json: {
        username,
        error: "API request failed",
        details: err.message
      }
    });
    continue;
  }

  // =====================================
  // FINAL RESULT
  // =====================================

  results.push({
    json: {
      username,
      date: targetDateString,
      problemsSolved: solvedProblems.length,
      solvedProblems: solvedProblems
    }
  });
}


// =====================================
// GUARANTEE SAFE OUTPUT (n8n REQUIRED)
// =====================================

if (results.length === 0) {
  return [
    {
      json: {
        message: "No valid input data received"
      }
    }
  ];
}

return results;
